import { afterEach, describe, expect, it, vi } from "vitest";
import { runLogin } from "./login.js";
const SIGN_IN_URL = "https://test.invalid/studio/sign-in?redirect_url=%2Fstudio%2Fclose";
const mockOpenStudioTo = vi.fn(async (_path, opts) => {
    opts.onLoginRequired?.("test-session", SIGN_IN_URL);
    return {
        abort: vi.fn(),
        done: Promise.resolve(),
        sessionId: "test-session",
    };
});
const mockRunLoginWindowMonitor = vi.fn().mockResolvedValue(undefined);
vi.mock("./openStudioTo.js", () => ({
    openStudioTo: (...args) => mockOpenStudioTo(...args),
    runLoginWindowMonitor: (...args) => mockRunLoginWindowMonitor(...args),
    StudioNavigationError: class StudioNavigationError extends Error {
    },
}));
// Default: the detached monitor spawn succeeds (returns a pid), so login hands
// off cleanup and exits without monitoring in-process.
const mockSpawnDetached = vi.fn().mockReturnValue(12345);
vi.mock("../browser.js", () => ({
    spawnDetached: (...args) => mockSpawnDetached(...args),
}));
let mockAuthenticated = false;
vi.mock("../config.js", () => ({
    getConfig: () => ({
        serviceUrl: "https://test.invalid",
        apiKey: mockAuthenticated ? "test-key" : null,
    }),
    hasCredentials: () => mockAuthenticated,
}));
vi.mock("../analytics.js", () => ({
    reportHandoff: vi.fn().mockResolvedValue(undefined),
}));
const platform = {};
afterEach(() => {
    vi.restoreAllMocks();
    mockOpenStudioTo.mockClear();
    mockRunLoginWindowMonitor.mockClear();
    mockSpawnDetached.mockClear();
    mockSpawnDetached.mockReturnValue(12345);
    mockAuthenticated = false;
});
function mockWhoAmI(ok) {
    return vi.spyOn(globalThis, "fetch").mockResolvedValue(ok
        ? new Response(JSON.stringify({
            user: { id: "u1", email: "ruven@goharvest.ai", fullName: null },
            organization: { id: "org1" },
        }), { status: 200 })
        : new Response(JSON.stringify({ error: "unauthorized" }), {
            status: 401,
        }));
}
describe("runLogin", () => {
    it("prints the sign-in URL so the user can open it manually", async () => {
        vi.spyOn(globalThis, "fetch").mockResolvedValue(new Response(JSON.stringify({
            user: { id: "u1", email: "ruven@goharvest.ai", fullName: null },
            organization: { id: "org1" },
        }), { status: 200 }));
        const log = vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        const printedUrl = log.mock.calls
            .map((call) => String(call[0]))
            .some((line) => line.includes(SIGN_IN_URL));
        expect(printedUrl).toBe(true);
    });
    it("targets Studio home for reuse and the self-closing page for a fresh window, in one call", async () => {
        // openStudioTo makes the reuse-vs-fresh decision from ONE pointer read;
        // runLogin must not pre-read the pointer to pick a destination (TOCTOU:
        // a reused window sent to the close page, or a throwaway window that
        // outlives login). It passes both destinations instead.
        vi.spyOn(globalThis, "fetch").mockResolvedValue(new Response(JSON.stringify({
            user: { id: "u1", email: "ruven@goharvest.ai", fullName: null },
            organization: { id: "org1" },
        }), { status: 200 }));
        vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        const path = String(mockOpenStudioTo.mock.calls[0]?.[0]);
        const opts = mockOpenStudioTo.mock.calls[0]?.[1];
        expect(path).toBe("/studio");
        expect(opts.freshWindowPath).toContain("autoClose=true");
        // openStudioTo owns session + pluginLogin injection on both paths.
        expect(path).not.toContain("pluginLogin");
        expect(opts.freshWindowPath).not.toContain("pluginLogin");
        // Login does NOT start an in-process monitor: it hands the close cleanup to
        // a detached child (or an in-process fallback), so no onEvent/monitor here.
        expect(opts.monitor).toBeUndefined();
        expect(opts.onEvent).toBeUndefined();
    });
    it("short-circuits when already authenticated with a verified key", async () => {
        mockAuthenticated = true;
        mockWhoAmI(true);
        const log = vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        // A no-op re-login must not open, navigate, or record anything.
        expect(mockOpenStudioTo).not.toHaveBeenCalled();
        const printed = log.mock.calls.map((c) => String(c[0])).join("\n");
        expect(printed).toContain("Already logged in as ruven@goharvest.ai");
        expect(printed).toContain("--force");
    });
    it("--force bypasses the short-circuit and ignores the stored key", async () => {
        mockAuthenticated = true;
        mockWhoAmI(true);
        vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", {
            exitOnComplete: false,
            force: true,
        });
        expect(mockOpenStudioTo).toHaveBeenCalledOnce();
        const opts = mockOpenStudioTo.mock.calls[0]?.[1];
        expect(opts.forceLogin).toBe(true);
    });
    it("falls through to a real login when the stored key fails verification", async () => {
        mockAuthenticated = true;
        mockWhoAmI(false);
        vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        // A stale key must never short-circuit (and never drive the
        // authenticated branch): the login flow runs with the key ignored.
        expect(mockOpenStudioTo).toHaveBeenCalledOnce();
        const opts = mockOpenStudioTo.mock.calls[0]?.[1];
        expect(opts.forceLogin).toBe(true);
    });
    it("hands the close-cleanup to a detached child and does NOT wait in-process", async () => {
        mockWhoAmI(true);
        vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        // Spawned a detached `--drain <sessionId>` child for cleanup...
        expect(mockSpawnDetached).toHaveBeenCalledOnce();
        const spawnArgs = mockSpawnDetached.mock.calls[0]?.[1];
        expect(spawnArgs).toContain("--drain");
        expect(spawnArgs).toContain("test-session");
        // ...so login did NOT block on the in-process monitor.
        expect(mockRunLoginWindowMonitor).not.toHaveBeenCalled();
    });
    it("falls back to the in-process monitor when the detached spawn fails", async () => {
        mockWhoAmI(true);
        mockSpawnDetached.mockReturnValue(null); // spawn could not be attempted
        vi.spyOn(console, "log").mockImplementation(() => { });
        await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        expect(mockSpawnDetached).toHaveBeenCalledOnce();
        // No detached child, so login monitors in-process before exiting.
        expect(mockRunLoginWindowMonitor).toHaveBeenCalledWith("test-session");
    });
    it("--drain mode runs only the window monitor, never the login flow", async () => {
        const originalArgv = process.argv;
        process.argv = [...originalArgv, "--drain", "sess-from-argv"];
        try {
            await runLogin(platform, "0.0.0-test", { exitOnComplete: false });
        }
        finally {
            process.argv = originalArgv;
        }
        expect(mockRunLoginWindowMonitor).toHaveBeenCalledWith("sess-from-argv");
        // It must not open Studio or spawn another child in drain mode.
        expect(mockOpenStudioTo).not.toHaveBeenCalled();
        expect(mockSpawnDetached).not.toHaveBeenCalled();
    });
    it("throws on a bare --drain with no sessionId rather than silently exiting", async () => {
        mockRunLoginWindowMonitor.mockClear();
        const originalArgv = process.argv;
        process.argv = [...originalArgv, "--drain"];
        try {
            await expect(runLogin(platform, "0.0.0-test", { exitOnComplete: false })).rejects.toThrow("requires a sessionId");
        }
        finally {
            process.argv = originalArgv;
        }
        expect(mockRunLoginWindowMonitor).not.toHaveBeenCalled();
    });
});
